/*!
 * Local lightweight Chart API shim for offline Electron packaging.
 * Supports the subset used by this app: line, bar, doughnut.
 */
(function (global) {
  'use strict';

  function toNum(v) {
    var n = Number(v);
    return Number.isFinite(n) ? n : 0;
  }

  function clear(canvas, ctx) {
    if (!canvas || !ctx) return;
    var ratio = global.devicePixelRatio || 1;
    var w = canvas.clientWidth || canvas.width || 640;
    var h = canvas.clientHeight || canvas.height || 320;
    canvas.width = Math.max(1, Math.floor(w * ratio));
    canvas.height = Math.max(1, Math.floor(h * ratio));
    ctx.setTransform(ratio, 0, 0, ratio, 0, 0);
    ctx.clearRect(0, 0, w, h);
  }

  function drawAxes(ctx, w, h, pad) {
    ctx.strokeStyle = '#cbd5e1';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(pad, pad);
    ctx.lineTo(pad, h - pad);
    ctx.lineTo(w - pad, h - pad);
    ctx.stroke();
  }

  function drawLineChart(ctx, w, h, data) {
    var labels = (data && data.labels) || [];
    var datasets = (data && data.datasets) || [];
    var pad = 28;
    drawAxes(ctx, w, h, pad);

    var max = 0;
    datasets.forEach(function (ds) {
      (ds.data || []).forEach(function (v) { max = Math.max(max, Math.abs(toNum(v))); });
    });
    if (max <= 0) max = 1;

    var n = Math.max(labels.length, 2);
    datasets.forEach(function (ds) {
      var vals = ds.data || [];
      ctx.strokeStyle = ds.borderColor || '#3b82f6';
      ctx.lineWidth = 2;
      ctx.beginPath();
      for (var i = 0; i < vals.length; i++) {
        var x = pad + (i * (w - pad * 2)) / (n - 1);
        var y = h - pad - (toNum(vals[i]) / max) * (h - pad * 2);
        if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
      }
      ctx.stroke();
    });
  }

  function drawBarChart(ctx, w, h, data) {
    var labels = (data && data.labels) || [];
    var datasets = (data && data.datasets) || [];
    var pad = 28;
    drawAxes(ctx, w, h, pad);
    if (!labels.length || !datasets.length) return;

    var max = 0;
    datasets.forEach(function (ds) {
      (ds.data || []).forEach(function (v) { max = Math.max(max, Math.abs(toNum(v))); });
    });
    if (max <= 0) max = 1;

    var groupW = (w - pad * 2) / labels.length;
    var barW = Math.max(4, (groupW * 0.8) / datasets.length);
    for (var i = 0; i < labels.length; i++) {
      for (var j = 0; j < datasets.length; j++) {
        var ds = datasets[j];
        var v = toNum((ds.data || [])[i]);
        var bh = Math.max(1, (Math.abs(v) / max) * (h - pad * 2));
        var x = pad + i * groupW + groupW * 0.1 + j * barW;
        var y = h - pad - bh;
        ctx.fillStyle = ds.backgroundColor || ds.borderColor || '#3b82f6';
        ctx.fillRect(x, y, barW - 1, bh);
      }
    }
  }

  function drawDoughnutChart(ctx, w, h, data) {
    var ds = ((data && data.datasets) || [])[0] || {};
    var vals = ds.data || [];
    if (!vals.length) return;
    var total = vals.reduce(function (s, v) { return s + Math.max(0, toNum(v)); }, 0);
    if (total <= 0) total = 1;

    var cx = w / 2;
    var cy = h / 2;
    var r = Math.max(24, Math.min(w, h) * 0.34);
    var inner = r * 0.58;
    var colors = ds.backgroundColor || [];
    var start = -Math.PI / 2;

    for (var i = 0; i < vals.length; i++) {
      var value = Math.max(0, toNum(vals[i]));
      var end = start + (Math.PI * 2 * value) / total;
      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.fillStyle = colors[i] || '#94a3b8';
      ctx.arc(cx, cy, r, start, end);
      ctx.closePath();
      ctx.fill();
      start = end;
    }

    ctx.beginPath();
    ctx.fillStyle = '#ffffff';
    ctx.arc(cx, cy, inner, 0, Math.PI * 2);
    ctx.fill();
  }

  function Chart(canvas, config) {
    this.canvas = canvas;
    this.ctx = canvas && canvas.getContext ? canvas.getContext('2d') : null;
    this.config = config || {};
    this._draw();
  }

  Chart.prototype._draw = function () {
    if (!this.canvas || !this.ctx) return;
    clear(this.canvas, this.ctx);
    var w = this.canvas.clientWidth || 640;
    var h = this.canvas.clientHeight || 320;
    var type = (this.config && this.config.type) || 'line';
    var data = (this.config && this.config.data) || {};
    if (type === 'bar') drawBarChart(this.ctx, w, h, data);
    else if (type === 'doughnut') drawDoughnutChart(this.ctx, w, h, data);
    else drawLineChart(this.ctx, w, h, data);
  };

  Chart.prototype.destroy = function () {
    if (!this.canvas || !this.ctx) return;
    clear(this.canvas, this.ctx);
  };

  global.Chart = Chart;
})(typeof window !== 'undefined' ? window : globalThis);
